CREATE ALGORITHM=UNDEFINED DEFINER=`u504097778_journey`@`127.0.0.1` SQL SECURITY DEFINER VIEW `vw_journey_search_blob`  AS SELECT `j`.`journey_id` AS `journey_id`, `j`.`journey_code` AS `journey_code`, convert(concat_ws(' ',(select group_concat(distinct concat(`ji`.`lang`,':',`ji`.`journey_name`,' ',coalesce(`ji`.`journey_description`,'')) separator ' ') from `journey_i18n` `ji` where `ji`.`journey_id` = `j`.`journey_id` and `ji`.`lang` in ('th','en','zh','ru','ar','hi','ms','ja')),(select group_concat(distinct concat(`pi`.`lang`,':',`pi`.`place_name`,' ',coalesce(`pi`.`place_desc_th`,'')) separator ' ') from (`journey_step` `js` join `place_i18n` `pi` on(`pi`.`place_id` = `js`.`place_id`)) where `js`.`journey_id` = `j`.`journey_id` and `pi`.`lang` in ('th','en','zh','ru','ar','hi','ms','ja')),(select group_concat(distinct concat(`t`.`tag_code`,':',`ti`.`lang`,':',`ti`.`tag_name`) separator ' ') from ((`journey_tag` `jt` join `md_tag` `t` on(`t`.`tag_id` = `jt`.`tag_id`)) join `md_tag_i18n` `ti` on(`ti`.`tag_id` = `t`.`tag_id`)) where `jt`.`journey_id` = `j`.`journey_id` and `ti`.`lang` in ('th','en','zh','ru','ar','hi','ms','ja')),(select group_concat(distinct concat(`ps`.`persona_code`,':',`pi2`.`lang`,':',`pi2`.`persona_name`) separator ' ') from (`journey_segment` `ps` join `md_persona_i18n` `pi2` on(`pi2`.`persona_code` = `ps`.`persona_code`)) where `ps`.`journey_id` = `j`.`journey_id` and `pi2`.`lang` in ('th','en','zh','ru','ar','hi','ms','ja')),(select group_concat(distinct concat(`mf`.`country_code`,':',`c`.`country_name_th`,'/',`c`.`country_name_en`) separator ' ') from (`journey_market_fit` `mf` join `md_country` `c` on(`c`.`country_code` = `mf`.`country_code`)) where `mf`.`journey_id` = `j`.`journey_id`)) using utf8mb4) FROM `journey` AS `j` WHERE `j`.`is_active` = 1 ;

