INSERT INTO `journey_i18n` (`journey_id`, `lang`, `journey_name`, `journey_name_th_inline`, `journey_description`, `persona_fit_note`, `earn_burn_boost_note`, `luxury_tone_th`, `luxury_tone_en`) VALUES
(1, 'ar', 'A1 – ماراثون طعام الشارع (سوق + مول + سوق ليلي)', 'A1 – สตรีทฟู้ดมาราธอน (ตลาด+ห้าง+ไนท์มาร์เก็ต)', 'مسار كامل ليوم واحد: أسواق ومول وسوق ليلي بقيمة ممتازة ودعم للشركاء المحليين.', NULL, NULL, 'Signature Street Gastronomy Circuit • คัดสรรร้านเด่นตลาด–มอลล์–ไนท์มาร์เก็ต • จบด้วยภารกิจและการเดินทางกลับอย่างสง่างาม', NULL),
(1, 'en', 'A1 – Street Food Marathon (Market + Mall + Night Market)', 'A1 – สตรีทฟู้ดมาราธอน (ตลาด+ห้าง+ไนท์มาร์เก็ต)', 'All-day street-food route across markets, malls, and night market. Great value; supports local partners.', NULL, NULL, 'Signature Street Gastronomy Circuit • คัดสรรร้านเด่นตลาด–มอลล์–ไนท์มาร์เก็ต • จบด้วยภารกิจและการเดินทางกลับอย่างสง่างาม', 'Luxury • A1 – Street Food Marathon (Market + Mall + Night Market)'),
(1, 'hi', 'A1 – स्ट्रीट फूड मैराथन (मार्केट + मॉल + नाइट मार्केट)', 'A1 – สตรีทฟู้ดมาราธอน (ตลาด+ห้าง+ไนท์มาร์เก็ต)', 'पूरा दिन: मार्केट/मॉल/नाइट मार्केट—बेहतरीन वैल्यू और लोकल पार्टनर्स को सपोर्ट।', NULL, NULL, 'Signature Street Gastronomy Circuit • คัดสรรร้านเด่นตลาด–มอลล์–ไนท์มาร์เก็ต • จบด้วยภารกิจและการเดินทางกลับอย่างสง่างาม', NULL),
(1, 'ja', 'A1 – 屋台グルメ・マラソン（市場＋モール＋ナイトマーケット）', 'A1 – สตรีทฟู้ดมาราธอน (ตลาด+ห้าง+ไนท์มาร์เก็ต)', '1日で食べ歩き：市場/モール/夜市。コスパ良く、地元パートナーも応援。', NULL, NULL, 'Signature Street Gastronomy Circuit • คัดสรรร้านเด่นตลาด–มอลล์–ไนท์มาร์เก็ต • จบด้วยภารกิจและการเดินทางกลับอย่างสง่างาม', NULL),
(1, 'ms', 'A1 – Maraton Makanan Jalanan (Pasar + Mall + Pasar Malam)', 'A1 – สตรีทฟู้ดมาราธอน (ตลาด+ห้าง+ไนท์มาร์เก็ต)', 'Sehari suntuk: pasar, mall, pasar malam—nilai terbaik dan sokong rakan niaga tempatan.', NULL, NULL, 'Signature Street Gastronomy Circuit • คัดสรรร้านเด่นตลาด–มอลล์–ไนท์มาร์เก็ต • จบด้วยภารกิจและการเดินทางกลับอย่างสง่างาม', NULL),
(1, 'ru', 'A1 – Марафон уличной еды (рынок + ТЦ + ночной рынок)', 'A1 – สตรีทฟู้ดมาราธอน (ตลาด+ห้าง+ไนท์มาร์เก็ต)', 'Целый день: рынки, ТЦ и ночной рынок. Отличная ценность, поддержка местных партнёров.', NULL, NULL, 'Signature Street Gastronomy Circuit • คัดสรรร้านเด่นตลาด–มอลล์–ไนท์มาร์เก็ต • จบด้วยภารกิจและการเดินทางกลับอย่างสง่างาม', NULL),
(1, 'th', 'A1 – สตรีทฟู้ดมาราธอน (ตลาด+ห้าง+ไนท์มาร์เก็ต)', NULL, 'กินทั้งวันแบบคุ้มค่า กระจายรายได้สู่ร้าน S/M/E/XL', NULL, NULL, 'Signature Street Gastronomy Circuit • คัดสรรร้านเด่นตลาด–มอลล์–ไนท์มาร์เก็ต • จบด้วยภารกิจและการเดินทางกลับอย่างสง่างาม', NULL),
(1, 'zh', 'A1 – 街头美食马拉松（市场+商场+夜市）', 'A1 – สตรีทฟู้ดมาราธอน (ตลาด+ห้าง+ไนท์มาร์เก็ต)', '一整天吃逛路线：市场/商场/夜市，高性价比，覆盖S/M/E/XL伙伴。', NULL, NULL, 'Signature Street Gastronomy Circuit • คัดสรรร้านเด่นตลาด–มอลล์–ไนท์มาร์เก็ต • จบด้วยภารกิจและการเดินทางกลับอย่างสง่างาม', NULL),
(2, 'ar', 'A2 – مسار مأكولات بحرية ناكلوا', 'A2 – เส้นทางซีฟู้ดนาเกลือ (Local Seafood Day)', 'سوق مأكولات بحرية + مطعم مشهور + مقهى حلويات. مناسب للعائلات ومحبي البحر.', NULL, NULL, 'Naklua Seafood Atelier • เลือกซีฟู้ดจากแหล่งคุณภาพสู่มื้อ Chef-style • เติมของหวานริมทะเล • ปิดทริปด้วย Safe Ride', NULL),
(2, 'en', 'A2 – Naklua Seafood Trail', 'A2 – เส้นทางซีฟู้ดนาเกลือ (Local Seafood Day)', 'Seafood market + famous seafood meal + dessert café. Perfect for seafood lovers and families.', NULL, NULL, 'Naklua Seafood Atelier • เลือกซีฟู้ดจากแหล่งคุณภาพสู่มื้อ Chef-style • เติมของหวานริมทะเล • ปิดทริปด้วย Safe Ride', 'Luxury • A2 – Naklua Seafood Trail'),
(2, 'hi', 'A2 – नाक्लुआ सीफ़ूड ट्रेल', 'A2 – เส้นทางซีฟู้ดนาเกลือ (Local Seafood Day)', 'सीफ़ूड मार्केट + फेमस सीफ़ूड मील + डेज़र्ट कैफ़े। फैमिली और सीफ़ूड लवर्स के लिए।', NULL, NULL, 'Naklua Seafood Atelier • เลือกซีฟู้ดจากแหล่งคุณภาพสู่มื้อ Chef-style • เติมของหวานริมทะเล • ปิดทริปด้วย Safe Ride', NULL),
(2, 'ja', 'A2 – ナクルア海鮮ルート', 'A2 – เส้นทางซีฟู้ดนาเกลือ (Local Seafood Day)', '海鮮市場＋人気海鮮ディナー＋デザートカフェ。海鮮好き・家族向け。', NULL, NULL, 'Naklua Seafood Atelier • เลือกซีฟู้ดจากแหล่งคุณภาพสู่มื้อ Chef-style • เติมของหวานริมทะเล • ปิดทริปด้วย Safe Ride', NULL),
(2, 'ms', 'A2 – Jejak Makanan Laut Naklua', 'A2 – เส้นทางซีฟู้ดนาเกลือ (Local Seafood Day)', 'Pasar makanan laut + restoran popular + kafe pencuci mulut. Sesuai untuk keluarga.', NULL, NULL, 'Naklua Seafood Atelier • เลือกซีฟู้ดจากแหล่งคุณภาพสู่มื้อ Chef-style • เติมของหวานริมทะเล • ปิดทริปด้วย Safe Ride', NULL),
(2, 'ru', 'A2 – Маршрут морепродуктов На Клуа', 'A2 – เส้นทางซีฟู้ดนาเกลือ (Local Seafood Day)', 'Рынок морепродуктов + популярный ужин + десерт-кафе. Для любителей морепродуктов и семей.', NULL, NULL, 'Naklua Seafood Atelier • เลือกซีฟู้ดจากแหล่งคุณภาพสู่มื้อ Chef-style • เติมของหวานริมทะเล • ปิดทริปด้วย Safe Ride', NULL),
(2, 'th', 'A2 – เส้นทางซีฟู้ดนาเกลือ (Local Seafood Day)', NULL, 'ตลาดลานโพธิ์ + ร้านดัง + คาเฟ่ + ดินเนอร์ริมทะเล', NULL, NULL, 'Naklua Seafood Atelier • เลือกซีฟู้ดจากแหล่งคุณภาพสู่มื้อ Chef-style • เติมของหวานริมทะเล • ปิดทริปด้วย Safe Ride', NULL),
(2, 'zh', 'A2 – 纳克鲁阿海鲜路线', 'A2 – เส้นทางซีฟู้ดนาเกลือ (Local Seafood Day)', '海鲜市场+人气海鲜餐+甜品咖啡，适合海鲜控与家庭。', NULL, NULL, 'Naklua Seafood Atelier • เลือกซีฟู้ดจากแหล่งคุณภาพสู่มื้อ Chef-style • เติมของหวานริมทะเล • ปิดทริปด้วย Safe Ride', NULL),
(3, 'ar', 'A4 – يوم عائلي للطعام (سوق عائم + مول)', 'A4 – Family Food Day (ตลาดน้ำ+ห้าง+ของหวาน)', 'مناسب للعائلة: سوق عائم، وجبات سهلة، تسوق في المول وحلويات.', NULL, NULL, 'Family Signature Day • ตลาดน้ำแบบพรีเมียม • พักสบายในมอลล์แลนด์มาร์ก • ของหวานสไตล์ Atelier สำหรับทุกวัย', NULL),
(3, 'en', 'A4 – Family Food Day (Floating Market + Mall + Dessert)', 'A4 – Family Food Day (ตลาดน้ำ+ห้าง+ของหวาน)', 'Family-friendly: floating market, easy dining, mall walk, and dessert stops.', NULL, NULL, 'Family Signature Day • ตลาดน้ำแบบพรีเมียม • พักสบายในมอลล์แลนด์มาร์ก • ของหวานสไตล์ Atelier สำหรับทุกวัย', 'Luxury • A4 – Family Food Day (Floating Market + Mall + Dessert)'),
(3, 'hi', 'A4 – फैमिली फूड डे (फ्लोटिंग मार्केट + मॉल + डेज़र्ट)', 'A4 – Family Food Day (ตลาดน้ำ+ห้าง+ของหวาน)', 'फैमिली-फ्रेंडली: फ्लोटिंग मार्केट, आसान मील, मॉल वॉक और डेज़र्ट।', NULL, NULL, 'Family Signature Day • ตลาดน้ำแบบพรีเมียม • พักสบายในมอลล์แลนด์มาร์ก • ของหวานสไตล์ Atelier สำหรับทุกวัย', NULL),
(3, 'ja', 'A4 – ファミリー美食デー（水上市場＋モール＋デザート）', 'A4 – Family Food Day (ตลาดน้ำ+ห้าง+ของหวาน)', '家族向け：水上市場、気軽な食事、モール散策とデザート。', NULL, NULL, 'Family Signature Day • ตลาดน้ำแบบพรีเมียม • พักสบายในมอลล์แลนด์มาร์ก • ของหวานสไตล์ Atelier สำหรับทุกวัย', NULL),
(3, 'ms', 'A4 – Hari Makan Keluarga (Pasar Terapung + Mall + Dessert)', 'A4 – Family Food Day (ตลาดน้ำ+ห้าง+ของหวาน)', 'Mesra keluarga: pasar terapung, makan mudah, jalan mall dan dessert.', NULL, NULL, 'Family Signature Day • ตลาดน้ำแบบพรีเมียม • พักสบายในมอลล์แลนด์มาร์ก • ของหวานสไตล์ Atelier สำหรับทุกวัย', NULL),
(3, 'ru', 'A4 – Семейный гастро‑день (плавучий рынок + ТЦ)', 'A4 – Family Food Day (ตลาดน้ำ+ห้าง+ของหวาน)', 'Для семьи: плавучий рынок, лёгкий обед, прогулка по ТЦ и десерты.', NULL, NULL, 'Family Signature Day • ตลาดน้ำแบบพรีเมียม • พักสบายในมอลล์แลนด์มาร์ก • ของหวานสไตล์ Atelier สำหรับทุกวัย', NULL),
